26	void ClientImpl::_InitializeClientInfo() {
27	  // get app name
28	  WCHAR exe_path[MAX_PATH] = {0};
29	  GetModuleFileName(NULL, exe_path, MAX_PATH);
30	  std::wstring path = exe_path;
31	  size_t separator_pos = path.find_last_of(L"\\/");
32	  if (separator_pos < path.size())
33	    app_name = path.substr(separator_pos + 1);
34	  else
35	    app_name = path;
36	  to_lower(app_name);
37	  // determine client type
38	  GetModuleFileName(GetCurrentModule(), exe_path, MAX_PATH);
39	  path = exe_path;
40	  to_lower(path);
41	  is_ime = ends_with(path, L".ime");
42	}
